/* ══ ECONOMIC CRIME DIRECTORY DATA ══ */
var intelligenceOrgs = [
  {"category":"Intelligence & Law Enforcement","name":"National Economic Crime Centre","acronym":"NECC","icon":"🇲","shortDesc":"Coordinates the UK’s operational response to serious and organised economic crime, bringing together law enforcement, government departments, regulators, and the private sector.","longDesc":"The NECC operates within the National Crime Agency and serves as the UK’s central coordinating body for tackling high-end economic crime. It brings together personnel from multiple agencies and private sector partners to deliver a unified national response. Its work spans intelligence development, threat assessment, and operational coordination across money laundering, fraud, bribery, and sanctions evasion. The centre plays a leading role in producing the UK National Risk Assessment for money laundering and terrorist financing.","whyMatters":"Understanding the NECC helps learners see how the UK structures its multi-agency response to economic crime and how intelligence coordination works across organisational boundaries.","geography":"UK National","type":"Law Enforcement & Intelligence","themes":["Money Laundering","Fraud & Organised Crime","Bribery & Corruption","Sanctions Evasion","Asset Recovery"],"website":"https://www.nationalcrimeagency.gov.uk/what-we-do/national-economic-crime-centre","keyResources":[{"title":"UK National Risk Assessment of ML & TF","url":"https://www.gov.uk/government/publications/national-risk-assessment-of-money-laundering-and-terrorist-financing-2020"},{"title":"NCA Annual Report","url":"https://www.nationalcrimeagency.gov.uk/who-we-are/publications"},{"title":"NCA Threat Assessments","url":"https://www.nationalcrimeagency.gov.uk/what-we-do/crime-threats"}],"attributionText":"Independent educational summary. Source: National Economic Crime Centre (NECC) / National Crime Agency, official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Intelligence & Law Enforcement","name":"UK Financial Intelligence Unit","acronym":"UKFIU","icon":"📊","shortDesc":"Receives, analyses, and disseminates suspicious activity reports (SARs) from the regulated sector to support law enforcement investigations across the UK.","longDesc":"The UKFIU sits within the NCA and is the UK’s designated financial intelligence unit under FATF standards. It serves as the central hub for receiving SARs from banks, accountants, solicitors, and other regulated entities. The unit analyses these reports to produce intelligence products that support investigations into money laundering, terrorist financing, and predicate offences. It also manages the Defence Against Money Laundering (DAML) consent regime and cooperates with international FIU counterparts through the Egmont Group.","whyMatters":"The UKFIU is central to understanding how suspicious activity reports flow from the private sector into law enforcement intelligence systems — a core mechanism in the UK’s AML framework.","geography":"UK National","type":"Financial Intelligence Unit (FIU)","themes":["Money Laundering","Fraud & Organised Crime","Sanctions Evasion"],"website":"https://www.nationalcrimeagency.gov.uk/what-we-do/crime-threats/money-laundering-and-illicit-finance/ukfiu","keyResources":[{"title":"UKFIU SARs Annual Report","url":"https://www.nationalcrimeagency.gov.uk/what-we-do/crime-threats/money-laundering-and-illicit-finance/ukfiu"},{"title":"SAR Glossary Codes & Guidance","url":"https://www.nationalcrimeagency.gov.uk/what-we-do/crime-threats/money-laundering-and-illicit-finance/ukfiu"}],"attributionText":"Independent educational summary. Source: UK Financial Intelligence Unit (UKFIU) / National Crime Agency, official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Intelligence & Law Enforcement","name":"National Fraud Intelligence Bureau","acronym":"NFIB","icon":"🛡️","shortDesc":"Collects and analyses fraud and cyber-enabled crime reports for the UK, providing intelligence packages to police forces for investigation.","longDesc":"The NFIB operates within the City of London Police and serves as the UK’s central intelligence authority for fraud and financially motivated cybercrime. It receives reports from Action Fraud (the public reporting service) and analyses them to identify serial offenders, organised crime groups, and emerging fraud trends. Intelligence packages are distributed to police forces for investigation, and the bureau produces regular strategic assessments of the fraud landscape.","whyMatters":"The NFIB demonstrates how fraud intelligence is centralised and prioritised in the UK system, and helps learners understand the pipeline from public reporting to police action.","geography":"UK National","type":"Law Enforcement & Intelligence","themes":["Fraud & Organised Crime","Emerging Threats (Crypto/AI)"],"website":"https://www.cityoflondon.police.uk/advice/advice-and-information/fa/fraud/nfib/","keyResources":[{"title":"NFIB Fraud Intelligence Publications","url":"https://www.cityoflondon.police.uk/advice/advice-and-information/fa/fraud/"},{"title":"Action Fraud Reporting Service","url":"https://www.actionfraud.police.uk/"}],"attributionText":"Independent educational summary. Source: National Fraud Intelligence Bureau (NFIB) / City of London Police, official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Intelligence & Law Enforcement","name":"CIFAS","acronym":"CIFAS","icon":"🔒","shortDesc":"A UK not-for-profit membership organisation focused on fraud prevention through data sharing, threat intelligence, and cross-sector collaboration.","longDesc":"CIFAS is a fraud prevention community that enables member organisations — spanning banking, insurance, retail, telecoms, and the public sector — to share data about confirmed fraud and financial crime. Through its National Fraud Database and other intelligence-sharing mechanisms, CIFAS helps members identify fraud risks, protect customers, and detect organised fraud networks. It also campaigns for better fraud awareness and produces annual research on fraud trends in the UK.","whyMatters":"CIFAS illustrates the role of private-sector collaboration and data sharing in fraud prevention — a model increasingly recognised internationally as essential to tackling economic crime.","geography":"UK National","type":"Public-Private Partnership","themes":["Fraud & Organised Crime","Money Laundering"],"website":"https://www.cifas.org.uk/","keyResources":[{"title":"Fraudscape Annual Report","url":"https://www.cifas.org.uk/research"},{"title":"CIFAS Intelligence Resources","url":"https://www.cifas.org.uk/intelligence"}],"attributionText":"Independent educational summary. Source: CIFAS, official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Intelligence & Law Enforcement","name":"Serious Fraud Office","acronym":"SFO","icon":"⚖️","shortDesc":"Investigates and prosecutes the most serious and complex cases of fraud, bribery, and corruption in England, Wales, and Northern Ireland.","longDesc":"The SFO is an independent UK government department with unique powers to both investigate and prosecute top-tier fraud, bribery, and corruption cases. Its jurisdiction covers cases of sufficient seriousness or complexity — often involving corporate wrongdoing, international bribery, or large-scale financial market manipulation. The SFO uses compulsory powers under the Criminal Justice Act 1987 and has a dedicated intelligence function to identify and assess potential cases aligned with its case acceptance criteria.","whyMatters":"The SFO helps learners understand how high-end corporate fraud and bribery are investigated and prosecuted, including the use of Deferred Prosecution Agreements (DPAs) as an enforcement tool.","geography":"UK National","type":"Law Enforcement & Intelligence","themes":["Fraud & Organised Crime","Bribery & Corruption","Asset Recovery"],"website":"https://www.sfo.gov.uk/","keyResources":[{"title":"SFO Annual Reports & Publications","url":"https://www.sfo.gov.uk/publications/"},{"title":"SFO Case Information","url":"https://www.sfo.gov.uk/our-cases/"},{"title":"SFO Operational Handbook (Public)","url":"https://www.sfo.gov.uk/publications/guidance-policy-and-protocols/"}],"attributionText":"Independent educational summary. Source: Serious Fraud Office (SFO), official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Intelligence & Law Enforcement","name":"Financial Conduct Authority","acronym":"FCA","icon":"🏦","shortDesc":"The UK’s conduct regulator for financial services firms, responsible for overseeing AML compliance and market integrity across the regulated sector.","longDesc":"The FCA regulates the conduct of approximately 42,000 financial services firms in the UK and is the AML/CFT supervisor for a large portion of the regulated sector. Its role in economic crime spans supervising firms’ anti-money laundering controls, enforcing market abuse regulations, and protecting consumers from financial fraud. The FCA publishes guidance, thematic reviews, and enforcement outcomes that shape industry practice.","whyMatters":"Understanding the FCA’s role is essential for anyone working in UK financial services compliance — it sets the supervisory expectations that firms must meet to prevent economic crime.","geography":"UK National","type":"Regulator","themes":["Money Laundering","Fraud & Organised Crime","Sanctions Evasion"],"website":"https://www.fca.org.uk/","keyResources":[{"title":"FCA Financial Crime Guide","url":"https://www.fca.org.uk/firms/financial-crime"},{"title":"FCA Enforcement Actions","url":"https://www.fca.org.uk/news/search-results?np_category=enforcement-actions"},{"title":"FCA Strategy & Annual Reports","url":"https://www.fca.org.uk/publications"}],"attributionText":"Independent educational summary. Source: Financial Conduct Authority (FCA), official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Intelligence & Law Enforcement","name":"Europol – European Financial and Economic Crime Centre","acronym":"EFECC","icon":"🇪🇺","shortDesc":"Europol’s dedicated centre for supporting EU member states in combating financial and economic crime through intelligence, analysis, and operational coordination.","longDesc":"The EFECC was established within Europol to strengthen the EU’s collective capacity to fight money laundering, fraud, corruption, counterfeiting, and intellectual property crime. It provides operational analysis, coordinates joint investigation teams, and supports cross-border operations. The centre also produces strategic threat assessments that inform EU policy priorities and resource allocation in the economic crime domain.","whyMatters":"The EFECC shows how European-level intelligence coordination works and why cross-border cooperation is critical for tackling financial crime that exploits jurisdictional boundaries.","geography":"European","type":"Law Enforcement & Intelligence","themes":["Money Laundering","Fraud & Organised Crime","Bribery & Corruption","Asset Recovery"],"website":"https://www.europol.europa.eu/crime-areas/economic-crime","keyResources":[{"title":"Europol Serious & Organised Crime Threat Assessment (SOCTA)","url":"https://www.europol.europa.eu/socta-report"},{"title":"Europol Financial Intelligence Publications","url":"https://www.europol.europa.eu/publications-events"}],"attributionText":"Independent educational summary. Source: Europol – European Financial and Economic Crime Centre (EFECC), official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Industry Body & Standards","name":"Financial Action Task Force","acronym":"FATF","icon":"🌐","shortDesc":"The global standard-setting body for anti-money laundering and counter-terrorist financing, producing recommendations, mutual evaluations, and risk assessments.","longDesc":"FATF is the inter-governmental body that sets international standards on combating money laundering, terrorist financing, and proliferation financing. Its 40 Recommendations form the global benchmark against which countries’ AML/CFT systems are assessed. FATF conducts mutual evaluation reviews, publishes typologies and guidance, and maintains lists identifying jurisdictions with strategic deficiencies. Its work shapes national legislation, supervisory practice, and private sector compliance globally.","whyMatters":"FATF standards underpin virtually every AML/CFT framework worldwide. Understanding FATF is foundational for anyone studying or working in the economic crime prevention field.","geography":"Global/International","type":"Standards Body","themes":["Money Laundering","Fraud & Organised Crime","Bribery & Corruption","Sanctions Evasion","Emerging Threats (Crypto/AI)"],"website":"https://www.fatf-gafi.org/","keyResources":[{"title":"FATF 40 Recommendations","url":"https://www.fatf-gafi.org/en/topics/fatf-recommendations.html"},{"title":"Mutual Evaluation Reports","url":"https://www.fatf-gafi.org/en/publications/mutualevaluations.html"},{"title":"FATF High-Risk Jurisdictions List","url":"https://www.fatf-gafi.org/en/countries/black-and-grey-lists.html"},{"title":"FATF Typologies & Guidance","url":"https://www.fatf-gafi.org/en/publications/methodsandtrends.html"}],"attributionText":"Independent educational summary. Source: Financial Action Task Force (FATF), official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Industry Body & Standards","name":"Egmont Group of Financial Intelligence Units","acronym":"Egmont Group","icon":"🌍","shortDesc":"A global network of 174 Financial Intelligence Units facilitating secure information exchange and international cooperation in the fight against money laundering and terrorist financing.","longDesc":"The Egmont Group connects FIUs worldwide through a secure communication platform (Egmont Secure Web) and provides a framework for intelligence sharing, capacity building, and best practice development. It enables FIUs to exchange financial intelligence rapidly and confidentially, supporting investigations into money laundering, terrorist financing, and associated predicate offences. The group also conducts research and publishes analyses that inform global AML/CFT standards and practices.","whyMatters":"The Egmont Group demonstrates why international FIU cooperation matters — financial crime is inherently cross-border, and intelligence must flow securely between jurisdictions to be effective.","geography":"Global/International","type":"Financial Intelligence Unit (FIU)","themes":["Money Laundering","Sanctions Evasion","Fraud & Organised Crime"],"website":"https://egmontgroup.org/","keyResources":[{"title":"Egmont Group Publications & Reports","url":"https://egmontgroup.org/egmont-documents/"},{"title":"Europe II Horizontal Analysis of IO.2 & IO.6","url":"https://egmontgroup.org/wp-content/uploads/2026/01/EUII-Group-Horizontal-Analysis-of-IO2-and-IO6-Final-version.pdf"},{"title":"Egmont Group Annual Report","url":"https://egmontgroup.org/egmont-documents/"}],"attributionText":"Independent educational summary. Source: Egmont Group of Financial Intelligence Units, official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Intelligence & Law Enforcement","name":"Joint Money Laundering Intelligence Taskforce","acronym":"JMLIT","icon":"🤝","shortDesc":"A UK public-private partnership enabling banks, law enforcement, and regulators to share intelligence on money laundering threats in real time.","longDesc":"JMLIT is a pioneering partnership between UK financial institutions, the NCA, and other law enforcement bodies that enables the real-time sharing of intelligence about suspected money laundering. Operating under a legal gateway provided by the Crime and Courts Act 2013, JMLIT allows banks to share customer information with each other and with law enforcement where there is a suspicion of money laundering. It also produces strategic threat assessments and typology reports that help the sector understand evolving threats.","whyMatters":"JMLIT is widely considered one of the most effective public-private intelligence-sharing models in the world, and is frequently cited as a template for similar initiatives globally.","geography":"UK National","type":"Public-Private Partnership","themes":["Money Laundering","Fraud & Organised Crime","Sanctions Evasion","Asset Recovery"],"website":"https://www.nationalcrimeagency.gov.uk/what-we-do/national-economic-crime-centre","keyResources":[{"title":"JMLIT Typology Reports","url":"https://www.nationalcrimeagency.gov.uk/what-we-do/national-economic-crime-centre"},{"title":"NCA Public-Private Partnerships","url":"https://www.nationalcrimeagency.gov.uk/what-we-do/crime-threats/money-laundering-and-illicit-finance"}],"attributionText":"Independent educational summary. Source: Joint Money Laundering Intelligence Taskforce (JMLIT) / National Crime Agency, official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Industry Body & Standards","name":"Transparency International UK","acronym":"TI-UK","icon":"💡","shortDesc":"An independent anti-corruption organisation campaigning for transparency in UK public and corporate life and publishing research on corruption risks.","longDesc":"Transparency International UK is the UK chapter of the global anti-corruption movement. It conducts independent research into corruption vulnerabilities in the UK — including in property markets, political finance, company formation, and overseas territories. TI-UK advocates for legal and regulatory reforms, publishes reports on illicit financial flows, and provides tools and guidance to support good governance. Its work informs both public debate and policy development.","whyMatters":"TI-UK provides a civil society perspective on corruption and economic crime that complements official law enforcement and regulatory views — essential for a well-rounded understanding.","geography":"UK National","type":"NGO & Think Tank","themes":["Bribery & Corruption","Money Laundering","Asset Recovery"],"website":"https://www.transparency.org.uk/","keyResources":[{"title":"TI-UK Research & Reports","url":"https://www.transparency.org.uk/research"},{"title":"Corruption Perceptions Index","url":"https://www.transparency.org/en/cpi"}],"attributionText":"Independent educational summary. Source: Transparency International UK (TI-UK), official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Industry Body & Standards","name":"Spotlight on Corruption","acronym":"SoC","icon":"🔦","shortDesc":"An independent UK-based civil society organisation dedicated to holding authorities accountable for tackling corruption and economic crime effectively.","longDesc":"Spotlight on Corruption monitors and evaluates the UK’s response to corruption and economic crime, producing analysis and policy recommendations. It scrutinises government policy, enforcement agency performance, and the effectiveness of the UK’s legal framework for tackling corruption. The organisation campaigns for stronger enforcement, greater transparency, and better resourcing of agencies tackling financial crime.","whyMatters":"Spotlight on Corruption offers an accountability lens on economic crime policy — helping learners understand the gap between policy ambition and practical enforcement outcomes.","geography":"UK National","type":"NGO & Think Tank","themes":["Bribery & Corruption","Asset Recovery","Money Laundering"],"website":"https://www.spotlightcorruption.org/","keyResources":[{"title":"SoC Research & Analysis","url":"https://www.spotlightcorruption.org/research/"},{"title":"SoC Policy Briefings","url":"https://www.spotlightcorruption.org/"}],"attributionText":"Independent educational summary. Source: Spotlight on Corruption (SoC), official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Industry Body & Standards","name":"UK Finance – Economic Crime Team","acronym":"UK Finance","icon":"🏦","shortDesc":"The trade body for UK banking and finance, whose economic crime team coordinates industry-wide intelligence sharing, threat assessments, and fraud prevention initiatives.","longDesc":"UK Finance represents nearly 300 firms across the UK banking and finance sector. Its economic crime division coordinates industry responses to fraud, money laundering, and cyber-enabled financial crime. The team produces annual fraud reports, manages intelligence-sharing protocols, and works with government and law enforcement on policy development. UK Finance also operates Take Five and other public awareness campaigns.","whyMatters":"UK Finance provides the industry perspective on economic crime trends and the effectiveness of prevention measures — essential context for understanding the private sector’s role.","geography":"UK National","type":"Professional Association","themes":["Fraud & Organised Crime","Money Laundering","Emerging Threats (Crypto/AI)"],"website":"https://www.ukfinance.org.uk/","keyResources":[{"title":"Annual Fraud Report","url":"https://www.ukfinance.org.uk/policy-and-guidance/reports-and-publications"},{"title":"Economic Crime Prevention Resources","url":"https://www.ukfinance.org.uk/our-expertise/economic-crime"}],"attributionText":"Independent educational summary. Source: UK Finance, official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Industry Body & Standards","name":"Basel Institute on Governance","acronym":"Basel Institute","icon":"🏛️","shortDesc":"An independent not-for-profit centre of excellence working on international anti-corruption, anti-money laundering, and asset recovery.","longDesc":"The Basel Institute on Governance is an independent Swiss-based organisation that combines research, policy advice, and operational support to strengthen governance and combat financial crime globally. It produces the Basel AML Index (a country-level ML/TF risk ranking), supports asset recovery in developing countries through the International Centre for Asset Recovery (ICAR), and delivers technical assistance to governments and international organisations.","whyMatters":"The Basel AML Index is a widely used risk assessment tool, and the Institute’s asset recovery work demonstrates the practical challenges of returning stolen assets to victim countries.","geography":"Global/International","type":"NGO & Think Tank","themes":["Money Laundering","Bribery & Corruption","Asset Recovery"],"website":"https://baselgovernance.org/","keyResources":[{"title":"Basel AML Index","url":"https://index.baselgovernance.org/"},{"title":"Asset Recovery Publications","url":"https://baselgovernance.org/publications"},{"title":"ICAR – International Centre for Asset Recovery","url":"https://baselgovernance.org/asset-recovery"}],"attributionText":"Independent educational summary. Source: Basel Institute on Governance, official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Industry Body & Standards","name":"Global Coalition to Fight Financial Crime","acronym":"GCFFC","icon":"🌟","shortDesc":"An international coalition of public, private, and non-profit organisations working together to improve the global fight against financial crime and illicit finance.","longDesc":"The GCFFC brings together banks, regulators, law enforcement agencies, and civil society organisations to advocate for reforms that make the global financial crime prevention system more effective. It focuses on improving information sharing between public and private sectors, strengthening beneficial ownership transparency, and leveraging technology for better detection. The coalition produces policy recommendations and convenes stakeholders at major international forums.","whyMatters":"The GCFFC embodies the growing consensus that no single sector can tackle financial crime alone — effective prevention requires structured collaboration between public, private, and civil society actors.","geography":"Global/International","type":"Public-Private Partnership","themes":["Money Laundering","Fraud & Organised Crime","Emerging Threats (Crypto/AI)"],"website":"https://www.gcffc.org/","keyResources":[{"title":"GCFFC Policy Papers","url":"https://www.gcffc.org/resources/"},{"title":"GCFFC Campaign Materials","url":"https://www.gcffc.org/"}],"attributionText":"Independent educational summary. Source: Global Coalition to Fight Financial Crime (GCFFC), official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Intelligence & Law Enforcement","name":"UNODC Corruption and Economic Crime Branch","acronym":"UNODC","icon":"🇺🇳","shortDesc":"The United Nations office responsible for supporting member states in preventing and combating corruption, money laundering, and economic crime through technical assistance and policy development.","longDesc":"The UNODC’s Corruption and Economic Crime Branch assists countries in implementing the UN Convention against Corruption (UNCAC) and develops tools, guidance, and technical assistance programmes to strengthen national AML/CFT frameworks. It supports legal reform, institution building, and capacity development, particularly in developing countries. The branch also conducts research on global corruption trends and the links between economic crime, organised crime, and development.","whyMatters":"UNODC provides the UN’s perspective on how economic crime undermines development and governance — connecting financial crime to broader human rights and development outcomes.","geography":"Global/International","type":"Standards Body","themes":["Bribery & Corruption","Money Laundering","Asset Recovery"],"website":"https://www.unodc.org/unodc/en/corruption/","keyResources":[{"title":"UN Convention Against Corruption (UNCAC)","url":"https://www.unodc.org/unodc/en/corruption/uncac.html"},{"title":"UNODC Publications on Economic Crime","url":"https://www.unodc.org/unodc/en/publications-by-topic.html"},{"title":"goAML Platform","url":"https://www.unodc.org/unodc/en/money-laundering/goAML/"}],"attributionText":"Independent educational summary. Source: United Nations Office on Drugs and Crime (UNODC), official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Industry Body & Standards","name":"ACAMS","acronym":"ACAMS","icon":"🎓","shortDesc":"The world’s largest professional association for anti-financial crime practitioners, providing training, certifications, and resources to the AML/CFT community.","longDesc":"ACAMS (Association of Certified Anti-Money Laundering Specialists) serves over 100,000 members across 180 jurisdictions. It offers professional certifications including the Certified Anti-Money Laundering Specialist (CAMS) designation, which is widely recognised as an industry benchmark. ACAMS also provides training programmes, conferences, publications, and a peer network for compliance professionals, law enforcement officers, and regulators working to prevent financial crime.","whyMatters":"ACAMS certifications and resources are among the most widely recognised professional development pathways in the economic crime field — valuable context for career planning.","geography":"Global/International","type":"Professional Association","themes":["Money Laundering","Sanctions Evasion","Fraud & Organised Crime","Emerging Threats (Crypto/AI)"],"website":"https://www.acams.org/","keyResources":[{"title":"CAMS Certification Overview","url":"https://www.acams.org/en/certifications/certified-anti-money-laundering-specialist"},{"title":"ACAMS Today (Publication)","url":"https://www.acams.org/en/resources/acams-today"},{"title":"ACAMS Research & Reports","url":"https://www.acams.org/en/resources"}],"attributionText":"Independent educational summary. Source: Association of Certified Anti-Money Laundering Specialists (ACAMS), official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Intelligence & Law Enforcement","name":"INTERPOL Financial Crime Unit","acronym":"INTERPOL FC","icon":"🔵","shortDesc":"INTERPOL’s specialist unit supporting international police cooperation on money laundering, financial fraud, corruption, and asset recovery across 196 member countries.","longDesc":"INTERPOL’s Financial Crime and Anti-Corruption Centre (IFCACC) provides operational support, analysis, and coordination for international police cooperation on financial crime. It assists member countries with multi-jurisdictional investigations, asset tracing, and the identification of criminal networks involved in money laundering, fraud, and corruption. INTERPOL also manages global police databases and communication networks that enable secure cross-border information sharing.","whyMatters":"INTERPOL demonstrates the practical mechanics of international police cooperation on financial crime — from red notices to coordinated operations targeting criminal assets across borders.","geography":"Global/International","type":"Law Enforcement & Intelligence","themes":["Fraud & Organised Crime","Money Laundering","Bribery & Corruption","Asset Recovery"],"website":"https://www.interpol.int/en/Crimes/Financial-crime","keyResources":[{"title":"INTERPOL Financial Crime Assessments","url":"https://www.interpol.int/en/Crimes/Financial-crime"},{"title":"INTERPOL Global Financial Crime Strategy","url":"https://www.interpol.int/en/Crimes/Financial-crime"},{"title":"INTERPOL Annual Report","url":"https://www.interpol.int/en/Resources/Documents"}],"attributionText":"Independent educational summary. Source: INTERPOL Financial Crime and Anti-Corruption Centre, official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Industry Body & Standards","name":"Wolfsberg Group","acronym":"Wolfsberg","icon":"🏦","shortDesc":"An association of thirteen global banks developing frameworks and guidance for managing financial crime risks, particularly in correspondent banking and KYC.","longDesc":"The Wolfsberg Group was formed in 2000 and comprises thirteen major international banks including Barclays, Citigroup, Deutsche Bank, Goldman Sachs, HSBC, JPMorgan Chase, and others. The group develops industry-standard guidance on AML, KYC, CTF, and sanctions screening. Its principles and questionnaires — particularly the Correspondent Banking Due Diligence Questionnaire (CBDDQ) — are widely used across the global financial sector.","whyMatters":"Wolfsberg standards are used daily by compliance teams worldwide. Understanding these frameworks is essential for anyone working in banking AML or correspondent banking due diligence.","geography":"Global/International","type":"Professional Association","themes":["Money Laundering","Sanctions Evasion"],"website":"https://www.wolfsberg-principles.com","keyResources":[{"title":"Wolfsberg AML Principles","url":"https://www.wolfsberg-principles.com/publications"},{"title":"Wolfsberg CBDDQ","url":"https://www.wolfsberg-principles.com/wolfsbergcb"},{"title":"Wolfsberg Guidance on Sanctions Screening","url":"https://www.wolfsberg-principles.com/publications"}],"attributionText":"Independent educational summary. Source: Wolfsberg Group official public resources. Accessed March 2026. Not endorsed by or affiliated with the Wolfsberg Group."},
  {"category":"Industry Body & Standards","name":"International Compliance Association","acronym":"ICA","icon":"📜","shortDesc":"A professional body offering globally recognised qualifications in governance, risk, and compliance, including specialist AML and financial crime certificates.","longDesc":"The ICA provides professional qualifications and training in compliance, AML, governance, and financial crime prevention. Its programmes are delivered in partnership with Alliance Manchester Business School and are recognised by regulators and employers worldwide. ICA qualifications range from foundation certificates through to postgraduate diplomas, covering AML, sanctions, fraud, and governance. The ICA also operates a membership network for compliance professionals.","whyMatters":"ICA qualifications are widely required or preferred by UK and international employers in compliance and financial crime roles. Their structured learning paths provide clear career progression routes.","geography":"Global/International","type":"Professional Association","themes":["Money Laundering","Fraud & Organised Crime","Bribery & Corruption","Sanctions Evasion"],"website":"https://www.int-comp.org","keyResources":[{"title":"ICA Qualifications Guide","url":"https://www.int-comp.org/qualifications/"},{"title":"ICA Professional Certifications","url":"https://www.int-comp.org/qualifications/"},{"title":"ICA Insights & Research","url":"https://www.int-comp.org/insights/"}],"attributionText":"Independent educational summary. Source: International Compliance Association official public resources. Accessed March 2026. Not endorsed by or affiliated with ICA."},
  {"category":"Industry Body & Standards","name":"Transparency International","acronym":"TI","icon":"📈","shortDesc":"The leading global civil society organisation fighting corruption through research, advocacy, and the annual Corruption Perceptions Index.","longDesc":"Transparency International was founded in 1993 and operates through over 100 national chapters worldwide. It publishes the Corruption Perceptions Index (CPI), the Global Corruption Barometer, and extensive research on beneficial ownership transparency, political integrity, and anti-bribery. TI’s UK chapter has been particularly influential in campaigning for unexplained wealth orders, a public register of overseas entities, and reforms to Companies House.","whyMatters":"TI’s Corruption Perceptions Index and research are fundamental reference tools for risk assessment in compliance. Understanding corruption risk geography is a core skill for AML professionals.","geography":"Global/International","type":"NGO & Think Tank","themes":["Bribery & Corruption","Money Laundering","Asset Recovery"],"website":"https://www.transparency.org","keyResources":[{"title":"Corruption Perceptions Index (CPI)","url":"https://www.transparency.org/en/cpi/2024"},{"title":"Global Corruption Barometer","url":"https://www.transparency.org/en/gcb"},{"title":"TI UK — Faulty Towers Report","url":"https://www.transparency.org.uk/publications/faulty-towers-understanding-impact-overseas-corruption-london-property-market"}],"attributionText":"Independent educational summary. Source: Transparency International official public resources. Accessed March 2026. Not endorsed by or affiliated with Transparency International."},
  {"category":"Industry Body & Standards","name":"Royal United Services Institute — Centre for Financial Crime","acronym":"RUSI CFC","icon":"🏛️","shortDesc":"An independent think tank producing influential research on financial crime policy, illicit finance, sanctions, and the effectiveness of the UK’s AML regime.","longDesc":"RUSI’s Centre for Financial Crime and Security Studies is one of the most respected research centres in the field. It produces policy analysis, convenes expert roundtables, and publishes reports that frequently influence UK and international policy. Key areas include the effectiveness of suspicious activity reporting, public-private partnerships, sanctions implementation, and the intersection of national security and financial crime.","whyMatters":"RUSI research frequently shapes UK policy and parliamentary debate on financial crime. Their publications provide excellent analytical depth for students and practitioners alike.","geography":"UK National","type":"NGO & Think Tank","themes":["Money Laundering","Sanctions Evasion","Fraud & Organised Crime","Emerging Threats (Crypto/AI)"],"website":"https://rusi.org/explore-our-research/topics/financial-crime","keyResources":[{"title":"RUSI Financial Crime Publications","url":"https://rusi.org/explore-our-research/topics/financial-crime"},{"title":"RUSI Occasional Papers on AML","url":"https://rusi.org/explore-our-research/topics/financial-crime"},{"title":"RUSI Future of Financial Intelligence Sharing (FFIS)","url":"https://ffis.rusi.org/"}],"attributionText":"Independent educational summary. Source: RUSI Centre for Financial Crime and Security Studies, official public resources. Accessed March 2026. Not endorsed by or affiliated with RUSI."},
  {"category":"Industry Body & Standards","name":"Association of Certified Fraud Examiners","acronym":"ACFE","icon":"🔎","shortDesc":"The world’s largest anti-fraud organisation, offering the CFE credential and publishing the global Report to the Nations on occupational fraud.","longDesc":"The ACFE was founded in 1988 and has over 90,000 members. It offers the Certified Fraud Examiner (CFE) credential, which covers fraud prevention, detection, investigation, and law. The ACFE’s biennial Report to the Nations provides comprehensive data on how occupational fraud is committed, detected, and the losses it causes. The organisation also provides extensive training, conferences, and local chapter events worldwide.","whyMatters":"The CFE credential is highly valued in fraud investigation and forensic accounting roles. The ACFE’s Report to the Nations is the most widely cited source on occupational fraud statistics globally.","geography":"Global/International","type":"Professional Association","themes":["Fraud & Organised Crime","Bribery & Corruption","Asset Recovery"],"website":"https://www.acfe.com","keyResources":[{"title":"ACFE Report to the Nations","url":"https://www.acfe.com/fraud-resources/reports-to-the-nations"},{"title":"CFE Certification Information","url":"https://www.acfe.com/become-a-cfe"},{"title":"ACFE Fraud Resources Library","url":"https://www.acfe.com/fraud-resources"}],"attributionText":"Independent educational summary. Source: ACFE official public resources. Accessed March 2026. Not endorsed by or affiliated with the ACFE."},
  {"category":"Key Resource & Framework","name":"FATF 40 Recommendations","acronym":"FATF Recs","icon":"📕","shortDesc":"The global standard for anti-money laundering and counter-terrorist financing — the foundation of every national AML/CFT legal framework worldwide.","longDesc":"First issued in 1990 and substantially revised in 2012, the FATF Recommendations provide a comprehensive framework covering the criminalisation of ML/TF, preventive measures for financial institutions and designated businesses, transparency of legal persons and arrangements, powers of competent authorities, and international cooperation. Countries are assessed against these standards through mutual evaluations. Non-compliance can result in FATF grey- or black-listing.","whyMatters":"Every AML law, regulation, and compliance programme in the world derives from these recommendations. They are the single most important document for anyone entering the field of financial crime prevention.","geography":"Global/International","type":"Standards Body","themes":["Money Laundering","Fraud & Organised Crime","Bribery & Corruption","Sanctions Evasion","Emerging Threats (Crypto/AI)"],"website":"https://www.fatf-gafi.org/en/topics/fatf-recommendations.html","keyResources":[{"title":"Full Text of the 40 Recommendations","url":"https://www.fatf-gafi.org/en/topics/fatf-recommendations.html"},{"title":"Interpretive Notes & Guidance","url":"https://www.fatf-gafi.org/en/topics/fatf-recommendations.html"},{"title":"FATF Methodology for Assessments","url":"https://www.fatf-gafi.org/en/publications/Mutualevaluations/Fatf-methodology.html"}],"attributionText":"Independent educational summary. Source: FATF official publications. Accessed March 2026. Not endorsed by the FATF."},
  {"category":"Key Resource & Framework","name":"UK Money Laundering Regulations","acronym":"UK MLR 2017","icon":"🇬🇧","shortDesc":"The UK’s primary AML/CFT legislation transposing EU directives, setting obligations for regulated firms on CDD, risk assessment, and suspicious activity reporting.","longDesc":"The Money Laundering, Terrorist Financing and Transfer of Funds (Information on the Payer) Regulations 2017 (as amended) form the backbone of the UK’s AML/CFT preventive regime. They mandate customer due diligence, ongoing monitoring, risk-based policies, SARs, and record-keeping for banks, accountants, estate agents, and other regulated entities. The regulations have been amended multiple times to reflect evolving EU and domestic requirements, including the Economic Crime (Transparency and Enforcement) Act 2022.","whyMatters":"These regulations directly govern what UK compliance officers must do day-to-day. Understanding them is mandatory for anyone working in or studying the UK AML framework.","geography":"UK National","type":"Regulator","themes":["Money Laundering","Fraud & Organised Crime","Sanctions Evasion"],"website":"https://www.legislation.gov.uk/uksi/2017/692/contents/made","keyResources":[{"title":"Full Text of MLR 2017","url":"https://www.legislation.gov.uk/uksi/2017/692/contents/made"},{"title":"HM Treasury MLR Guidance","url":"https://www.gov.uk/government/collections/money-laundering-regulations-guidance"},{"title":"JMLSG Guidance","url":"https://www.jmlsg.org.uk/guidance/current-guidance/"}],"attributionText":"Independent educational summary. Source: UK legislation.gov.uk. Accessed March 2026. Crown Copyright. Open Government Licence v3.0."},
  {"category":"Key Resource & Framework","name":"US Bank Secrecy Act & AML Framework","acronym":"BSA/AML","icon":"🇺🇸","shortDesc":"The foundation of US anti-money laundering law, requiring financial institutions to maintain AML programmes, file SARs, and report large cash transactions.","longDesc":"The Bank Secrecy Act (1970) and its amendments — including the USA PATRIOT Act (2001), the Anti-Money Laundering Act (2020), and the Corporate Transparency Act — create the US AML/CFT framework administered by FinCEN. Requirements include AML compliance programmes, Currency Transaction Reports (CTRs), Suspicious Activity Reports (SARs), and beneficial ownership reporting. Enforcement is shared across FinCEN, DOJ, federal banking regulators, and the SEC.","whyMatters":"The US AML framework has global reach through correspondent banking relationships and dollar-clearing obligations. Understanding BSA/AML is essential for anyone working in international financial compliance.","geography":"Global/International","type":"Regulator","themes":["Money Laundering","Fraud & Organised Crime","Sanctions Evasion","Emerging Threats (Crypto/AI)"],"website":"https://www.fincen.gov/resources/statutes-and-regulations/bank-secrecy-act","keyResources":[{"title":"FinCEN BSA Resources","url":"https://www.fincen.gov/resources/statutes-and-regulations/bank-secrecy-act"},{"title":"FinCEN Advisories & Guidance","url":"https://www.fincen.gov/resources/advisories"},{"title":"FFIEC BSA/AML Examination Manual","url":"https://bsaaml.ffiec.gov/manual"}],"attributionText":"Independent educational summary. Source: FinCEN, US public domain resources under 17 U.S.C. § 105. Accessed March 2026."},
  {"category":"Key Resource & Framework","name":"FBI Internet Crime Complaint Center Annual Report","acronym":"FBI IC3 Report","icon":"📊","shortDesc":"The FBI’s annual report on internet-facilitated crime, providing the most comprehensive dataset on financial fraud losses, trends, and victim demographics in the US.","longDesc":"The IC3 Annual Report compiles data from hundreds of thousands of complaints received each year about internet-facilitated financial crime. It covers BEC, investment fraud, romance scams, ransomware, crypto fraud, and many other categories. The 2024 report documented record losses of $16.6 billion, with investment fraud and BEC as the costliest categories. The report provides invaluable trend data and is widely cited by regulators, researchers, and compliance professionals.","whyMatters":"IC3 data is the most authoritative source on US financial fraud trends and scale. Its typology breakdowns and loss figures are essential reference material for fraud prevention professionals.","geography":"Global/International","type":"Law Enforcement & Intelligence","themes":["Fraud & Organised Crime","Emerging Threats (Crypto/AI)"],"website":"https://www.ic3.gov","keyResources":[{"title":"IC3 2024 Annual Report (PDF)","url":"https://www.ic3.gov/AnnualReport/Reports/2024_IC3Report.pdf"},{"title":"IC3 Public Service Announcements","url":"https://www.ic3.gov/PSA"},{"title":"IC3 Complaint Referral Form","url":"https://www.ic3.gov/Home/ComplaintChoice"}],"attributionText":"Independent educational summary. Source: FBI IC3, US public domain resources under 17 U.S.C. § 105. Accessed March 2026."},
  {"category":"Key Resource & Framework","name":"UK National Risk Assessment of ML & TF","acronym":"UK NRA","icon":"📉","shortDesc":"HM Treasury and Home Office’s comprehensive assessment of money laundering and terrorist financing risks facing the UK — required reading for compliance professionals.","longDesc":"Published periodically (most recently in 2020), the UK NRA provides an authoritative government assessment of ML/TF threats, vulnerabilities, and the effectiveness of mitigating controls across all regulated sectors. It examines risks by typology (cash-based ML, professional enablers, property, etc.) and by sector (banking, legal, accountancy, estate agents, etc.). The NRA feeds directly into firm-level risk assessments that regulated entities are required to maintain under the Money Laundering Regulations.","whyMatters":"The NRA is the UK government’s official view of where ML/TF risks are highest. Compliance officers use it to inform their own firm-wide risk assessments, making it a foundational document for UK AML practice.","geography":"UK National","type":"Regulator","themes":["Money Laundering","Fraud & Organised Crime","Sanctions Evasion"],"website":"https://www.gov.uk/government/publications/national-risk-assessment-of-money-laundering-and-terrorist-financing-2020","keyResources":[{"title":"UK NRA 2020 (Full Report)","url":"https://www.gov.uk/government/publications/national-risk-assessment-of-money-laundering-and-terrorist-financing-2020"},{"title":"HM Treasury AML/CFT Supervision Reports","url":"https://www.gov.uk/government/collections/anti-money-laundering-and-counter-terrorist-financing-supervision-reports"}],"attributionText":"Independent educational summary. Source: HM Treasury / Home Office official publication. Crown Copyright. Open Government Licence v3.0. Accessed March 2026."},
  {"category":"Key Resource & Framework","name":"EU Anti-Money Laundering Directives","acronym":"EU AMLD","icon":"🇪🇺","shortDesc":"The series of EU directives (currently 6AMLD) harmonising anti-money laundering rules across member states, with an AML Authority (AMLA) launching in 2025.","longDesc":"The EU has enacted six Anti-Money Laundering Directives since 1991, progressively expanding the scope and rigour of AML/CFT obligations. The 6th AMLD (2018/1673) harmonised the definition of ML offences, extended criminal liability, and increased penalties. In 2024, the EU agreed a new AML Package establishing the Anti-Money Laundering Authority (AMLA) based in Frankfurt, a directly applicable AML Regulation, and updated transfer-of-funds rules. AMLA will directly supervise the highest-risk cross-border financial entities from 2025.","whyMatters":"EU AML directives shape the regulatory environment across 27 member states and continue to influence UK and global AML standards. Understanding this framework is essential for cross-border compliance roles.","geography":"European","type":"Regulator","themes":["Money Laundering","Bribery & Corruption","Sanctions Evasion","Emerging Threats (Crypto/AI)"],"website":"https://finance.ec.europa.eu/financial-crime/anti-money-laundering-and-countering-financing-terrorism_en","keyResources":[{"title":"EU AML Package Overview","url":"https://finance.ec.europa.eu/financial-crime/anti-money-laundering-and-countering-financing-terrorism_en"},{"title":"6th AMLD Full Text","url":"https://eur-lex.europa.eu/legal-content/EN/TXT/?uri=celex:32018L1673"},{"title":"AMLA Information","url":"https://finance.ec.europa.eu/financial-crime/eu-anti-money-laundering-authority-amla_en"}],"attributionText":"Independent educational summary. Source: European Commission official publications. Accessed March 2026. Not endorsed by the European Commission."},
  {"category":"Key Resource & Framework","name":"ACFE Report to the Nations","acronym":"RTTN","icon":"📝","shortDesc":"The world’s largest study of occupational fraud, analysing 1,900+ real cases to reveal how internal fraud is committed, detected, and how much it costs organisations.","longDesc":"Published biennially by the ACFE since 1996, the Report to the Nations analyses data from Certified Fraud Examiners who have investigated real cases of occupational fraud worldwide. The 2024 edition analysed 1,921 cases across 138 countries. Key findings include that organisations lose an estimated 5% of revenue to fraud annually, the median loss per case is $145,000, and most frauds are detected through tips rather than audits. The report breaks down schemes by type (asset misappropriation, corruption, financial statement fraud), industry, region, and detection method.","whyMatters":"This report provides the most authoritative global data on occupational fraud. It is an essential reference for fraud prevention, internal audit, and compliance professionals building the business case for anti-fraud controls.","geography":"Global/International","type":"Professional Association","themes":["Fraud & Organised Crime","Bribery & Corruption"],"website":"https://www.acfe.com/fraud-resources/reports-to-the-nations","keyResources":[{"title":"Report to the Nations 2024","url":"https://www.acfe.com/fraud-resources/reports-to-the-nations"},{"title":"ACFE Fraud Tree (Classification)","url":"https://www.acfe.com/fraud-resources"},{"title":"Interactive RTTN Data Explorer","url":"https://www.acfe.com/fraud-resources/reports-to-the-nations"}],"attributionText":"Independent educational summary. Source: ACFE official publications. Accessed March 2026. Not endorsed by or affiliated with the ACFE."},
  {"category":"Industry Body & Standards","name":"Stop the Traffik","acronym":"STT","icon":"🚫","shortDesc":"A global intelligence-led prevention organisation that disrupts human trafficking by working with banks, businesses, communities, and law enforcement to spot the signs.","longDesc":"Stop the Traffik is a UK-headquartered NGO that takes an intelligence-led approach to preventing human trafficking and modern slavery. It partners with major banks and financial institutions to identify trafficking-related transaction patterns, runs community awareness programmes, and operates STOP APP — a tool allowing anyone to report suspected trafficking activity. The organisation works across supply chains, the financial sector, and local communities to build a network of informed responders. Its Centre for Intelligence-Led Prevention (CfILP) analyses data from diverse sources to produce actionable intelligence.","whyMatters":"Stop the Traffik demonstrates the intersection between financial crime and human exploitation. Its banking partnerships show how transaction monitoring and SAR reporting can directly help identify and rescue trafficking victims.","geography":"Global/International","type":"NGO & Think Tank","themes":["Fraud & Organised Crime","Money Laundering"],"website":"https://www.stopthetraffik.org/","keyResources":[{"title":"Stop the Traffik Resources Hub","url":"https://www.stopthetraffik.org/resources/"},{"title":"STOP APP — Report Trafficking","url":"https://www.stopthetraffik.org/stopapp/"},{"title":"Finance Against Trafficking Initiative","url":"https://www.stopthetraffik.org/what-we-do/partnerships/"}],"attributionText":"Independent educational summary. Source: Stop the Traffik official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Industry Body & Standards","name":"Slave Free Alliance","acronym":"SFA","icon":"⛓️","shortDesc":"A social enterprise and membership initiative of Hope for Justice, helping businesses, organisations, and individuals take practical steps to prevent modern slavery in operations and supply chains.","longDesc":"The Slave Free Alliance was established by the international anti-slavery charity Hope for Justice. It provides membership-based support, training, assessments, and consultancy to help organisations identify and address modern slavery risks in their operations and supply chains. Members include businesses across multiple sectors who commit to proactive steps beyond basic compliance with the Modern Slavery Act 2015. The Alliance also delivers awareness training and produces guidance for frontline staff in sectors at high risk of encountering exploitation.","whyMatters":"Modern slavery is a predicate offence for money laundering. Understanding how slavery manifests in legitimate supply chains helps compliance professionals recognise the financial flows and business structures that may conceal exploitation.","geography":"UK National","type":"NGO & Think Tank","themes":["Fraud & Organised Crime","Money Laundering","Bribery & Corruption"],"website":"https://www.slavefreealliance.org/","keyResources":[{"title":"Slave Free Alliance Membership","url":"https://www.slavefreealliance.org/membership/"},{"title":"Modern Slavery Training & Resources","url":"https://www.slavefreealliance.org/training/"},{"title":"Hope for Justice — Research","url":"https://hopeforjustice.org/research/"}],"attributionText":"Independent educational summary. Source: Slave Free Alliance / Hope for Justice official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Industry Body & Standards","name":"Get Safe Online","acronym":"GSO","icon":"🛡️","shortDesc":"The UK's leading source of unbiased, factual, and easy-to-understand information on online safety, helping individuals and small businesses protect themselves from fraud and cybercrime.","longDesc":"Get Safe Online is a UK-based not-for-profit organisation backed by the government and leading private sector organisations. It provides free, expert advice on protecting against online fraud, identity theft, phishing, malware, and other cyber-enabled economic crimes. The platform covers topics from safe online shopping and banking to social media privacy and business cybersecurity. It also runs annual awareness campaigns including Get Safe Online Week and produces resources tailored for vulnerable groups.","whyMatters":"Online fraud is now the most common crime type in the UK. Get Safe Online bridges the gap between technical cybersecurity and public understanding — a vital resource for fraud prevention education at community level.","geography":"UK National","type":"NGO & Think Tank","themes":["Fraud & Organised Crime","Emerging Threats (Crypto/AI)"],"website":"https://www.getsafeonline.org/","keyResources":[{"title":"Get Safe Online — Personal Safety Guides","url":"https://www.getsafeonline.org/personal/"},{"title":"Get Safe Online — Business Safety Guides","url":"https://www.getsafeonline.org/business/"},{"title":"Fraud Awareness Resources","url":"https://www.getsafeonline.org/"}],"attributionText":"Independent educational summary. Source: Get Safe Online official public resources. Crown Copyright where applicable. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Industry Body & Standards","name":"Crimestoppers","acronym":"Crimestoppers","icon":"📞","shortDesc":"An independent UK charity enabling people to report crime and criminal activity anonymously, including fraud, money laundering, and financial crime.","longDesc":"Crimestoppers is a UK charity that operates an anonymous reporting service — by phone (0800 555 111) and online — allowing members of the public to pass on information about crime without giving their identity. It plays a significant role in gathering intelligence on fraud, money laundering, drug trafficking, and other economic crimes. The charity works closely with law enforcement and has helped solve numerous high-profile cases. Crimestoppers also runs targeted campaigns to raise awareness of specific crime types including fraud and modern slavery.","whyMatters":"Anonymous reporting is a critical intelligence source for law enforcement tackling economic crime. Crimestoppers provides a safe channel for whistleblowers and members of the public who may have crucial information but fear retaliation.","geography":"UK National","type":"NGO & Think Tank","themes":["Fraud & Organised Crime","Money Laundering"],"website":"https://crimestoppers-uk.org/","keyResources":[{"title":"Report a Crime Anonymously","url":"https://crimestoppers-uk.org/give-information"},{"title":"Crimestoppers Campaigns","url":"https://crimestoppers-uk.org/campaigns"},{"title":"Fraud & Financial Crime Resources","url":"https://crimestoppers-uk.org/keeping-safe/money-fraud"}],"attributionText":"Independent educational summary. Source: Crimestoppers official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Industry Body & Standards","name":"Anti-Slavery International","acronym":"ASI","icon":"✊","shortDesc":"The world's oldest international human rights organisation focused on eliminating all forms of slavery, trafficking, and forced labour worldwide.","longDesc":"Founded in 1839, Anti-Slavery International is the world's oldest human rights organisation. It works to eliminate slavery, human trafficking, forced labour, and child labour globally through research, advocacy, and partnerships with local organisations. In the UK context, it has been instrumental in campaigning for stronger modern slavery legislation and corporate supply chain transparency. The organisation publishes research on the links between modern slavery and financial systems, and advocates for better use of financial intelligence to detect exploitation.","whyMatters":"Modern slavery generates an estimated $150 billion in illegal profits globally. Understanding its financial dimensions — from labour exploitation in supply chains to the laundering of proceeds — is increasingly important for compliance professionals.","geography":"Global/International","type":"NGO & Think Tank","themes":["Fraud & Organised Crime","Money Laundering","Bribery & Corruption"],"website":"https://www.antislavery.org/","keyResources":[{"title":"Anti-Slavery International Research","url":"https://www.antislavery.org/what-we-do/research/"},{"title":"Modern Slavery & Supply Chains","url":"https://www.antislavery.org/what-we-do/uk/"},{"title":"Global Slavery Index (Walk Free)","url":"https://www.walkfree.org/global-slavery-index/"}],"attributionText":"Independent educational summary. Source: Anti-Slavery International official public resources. Accessed March 2026. Not endorsed by or affiliated with the organisation."},
  {"category":"Key Resource & Framework","name":"Joint Money Laundering Steering Group Guidance","acronym":"JMLSG","icon":"📘","shortDesc":"The UK financial sector’s comprehensive AML/CFT guidance, approved by HM Treasury, covering all regulated sectors from banking to crypto-asset service providers.","longDesc":"The JMLSG Guidance is produced by an industry body representing major UK trade associations in the financial sector. It provides detailed, sector-specific guidance on how to comply with the UK Money Laundering Regulations, covering customer due diligence, ongoing monitoring, suspicious activity reporting, and record-keeping. The guidance is approved by HM Treasury and courts treat it as the benchmark for what constitutes reasonable AML compliance in the UK. It is regularly updated to cover new risks including crypto assets and electronic money.","whyMatters":"JMLSG Guidance is the practical ‘how-to’ manual for UK financial sector AML compliance. It translates legal obligations into actionable procedures and is the key reference document for compliance teams.","geography":"UK National","type":"Professional Association","themes":["Money Laundering","Fraud & Organised Crime","Sanctions Evasion"],"website":"https://www.jmlsg.org.uk","keyResources":[{"title":"JMLSG Current Guidance (Parts I & II)","url":"https://www.jmlsg.org.uk/guidance/current-guidance/"},{"title":"JMLSG Sector-Specific Chapters","url":"https://www.jmlsg.org.uk/guidance/current-guidance/"},{"title":"JMLSG Good Practice Guidance","url":"https://www.jmlsg.org.uk/guidance/current-guidance/"}],"attributionText":"Independent educational summary. Source: JMLSG official public guidance. Accessed March 2026. Not endorsed by or affiliated with the JMLSG."}
];
